import React, { useEffect, useState } from 'react';
import api from '../utils/api';

export default function MyBorrows() {
  const [borrows, setBorrows]   = useState<any[]>([]);
  const [requests, setRequests] = useState<any[]>([]);
  const [loading, setLoading]   = useState(true);
  const [tab, setTab] = useState<'borrows'|'requests'>('requests');

  useEffect(() => {
    Promise.all([api.get('/borrows/my'), api.get('/borrows/my-requests')])
      .then(([b,r]) => { setBorrows(b.data.data||[]); setRequests(r.data.data||[]); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  const pendingCount = requests.filter(r=>r.status==='pending').length;

  const statusStyle = (s: string, type: 'borrow'|'req') => {
    const map: any = {
      borrowed:  { bg:'rgba(251,191,36,0.1)',  color:'#fbbf24' },
      returned:  { bg:'rgba(52,211,153,0.1)',  color:'#34d399' },
      overdue:   { bg:'rgba(248,113,113,0.1)', color:'#f87171' },
      pending:   { bg:'rgba(251,191,36,0.1)',  color:'#fbbf24' },
      approved:  { bg:'rgba(52,211,153,0.1)',  color:'#34d399' },
      rejected:  { bg:'rgba(248,113,113,0.1)', color:'#f87171' },
    };
    return map[s] || { bg:'rgba(255,255,255,0.08)', color:'rgba(255,255,255,0.4)' };
  };

  return (
    <div className="page-enter" style={{padding:'32px 40px',width:'100%'}}>

      {/* Header */}
      <div style={{marginBottom:30}}>
        <h1 style={{fontFamily:"'Playfair Display',serif",fontSize:32,fontWeight:700,color:'#fff'}}>My Library</h1>
        <p style={{color:'rgba(255,255,255,0.3)',fontSize:14,marginTop:6}}>Your borrow history and requests</p>
      </div>

      {/* Tabs */}
      <div style={{display:'flex',gap:8,marginBottom:26}}>
        {(['requests','borrows'] as const).map(t=>(
          <button key={t} onClick={()=>setTab(t)}
            style={{padding:'10px 22px',background:tab===t?'#c9a84c':'rgba(255,255,255,0.05)',color:tab===t?'#1a1a2e':'rgba(255,255,255,0.45)',border:tab===t?'none':'1px solid rgba(255,255,255,0.08)',borderRadius:10,fontSize:14,fontWeight:700,fontFamily:'inherit',transition:'all .2s',display:'flex',alignItems:'center',gap:8}}>
            {t==='requests'?'My Requests':'Borrowed Books'}
            {t==='requests' && pendingCount>0 && (
              <span style={{background:tab==='requests'?'#1a1a2e':'#c9a84c',color:tab==='requests'?'#c9a84c':'#1a1a2e',borderRadius:99,padding:'1px 8px',fontSize:11,fontWeight:800}}>{pendingCount}</span>
            )}
          </button>
        ))}
      </div>

      {loading ? (
        <div style={{display:'flex',justifyContent:'center',padding:80}}>
          <div style={{width:32,height:32,border:'3px solid #c9a84c',borderTopColor:'transparent',borderRadius:'50%',animation:'spin 1s linear infinite'}}/>
        </div>
      ) : tab==='requests' ? (
        requests.length ? (
          <div style={{display:'grid',gap:12}}>
            {requests.map(r=>{
              const st = statusStyle(r.status,'req');
              return (
                <div key={r.id} style={{background:'#11112a',border:'1px solid rgba(255,255,255,0.07)',borderRadius:16,padding:'20px 22px',display:'flex',alignItems:'center',gap:20}}>
                  {/* Status dot */}
                  <div style={{width:10,height:10,borderRadius:'50%',background:st.color,boxShadow:`0 0 8px ${st.color}88`,flexShrink:0}}/>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontSize:16,fontWeight:700,color:'#fff',marginBottom:4,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{r.title}</div>
                    <div style={{fontSize:13,color:'rgba(255,255,255,0.35)'}}>{r.author}</div>
                    <div style={{fontSize:12,color:'rgba(255,255,255,0.22)',marginTop:6}}>
                      Requested: {new Date(r.request_date).toLocaleDateString('en-GB',{day:'numeric',month:'short',year:'numeric'})}
                    </div>
                  </div>
                  <div style={{textAlign:'right',flexShrink:0}}>
                    <span style={{fontSize:12,fontWeight:700,padding:'5px 14px',borderRadius:99,background:st.bg,color:st.color,display:'inline-block',textTransform:'capitalize'}}>
                      {r.status==='pending'?'Pending':r.status==='approved'?'Approved':'Rejected'}
                    </span>
                    {r.reject_reason && (
                      <div style={{fontSize:11,color:'#f87171',marginTop:6,maxWidth:180,textAlign:'right'}}>Reason: {r.reject_reason}</div>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        ) : (
          <div style={{textAlign:'center',padding:'80px 0',color:'rgba(255,255,255,0.2)'}}>
            <div style={{fontSize:14,marginBottom:8,fontStyle:'italic'}}>No requests yet</div>
            <div style={{fontSize:13,color:'rgba(255,255,255,0.15)'}}>Go to Books page and click "Request Borrow"</div>
          </div>
        )
      ) : (
        borrows.length ? (
          <div style={{display:'grid',gap:12}}>
            {borrows.map(b=>{
              const st = statusStyle(b.status,'borrow');
              const isOverdue = b.status==='overdue';
              return (
                <div key={b.id} style={{background:'#11112a',border:`1px solid ${isOverdue?'rgba(248,113,113,0.2)':'rgba(255,255,255,0.07)'}`,borderRadius:16,padding:'20px 22px',display:'flex',alignItems:'center',gap:20}}>
                  <div style={{width:10,height:10,borderRadius:'50%',background:st.color,boxShadow:`0 0 8px ${st.color}88`,flexShrink:0}}/>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontSize:16,fontWeight:700,color:'#fff',marginBottom:4,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{b.title}</div>
                    <div style={{fontSize:13,color:'rgba(255,255,255,0.35)'}}>{b.author}</div>
                    <div style={{fontSize:12,color:'rgba(255,255,255,0.22)',marginTop:6}}>
                      Due: {b.due_date?.split('T')[0]}
                    </div>
                  </div>
                  <div style={{textAlign:'right',flexShrink:0}}>
                    <span style={{fontSize:12,fontWeight:700,padding:'5px 14px',borderRadius:99,background:st.bg,color:st.color,display:'inline-block',textTransform:'capitalize',marginBottom:b.fine_amount>0?6:0}}>{b.status}</span>
                    {b.fine_amount>0 && (
                      <div style={{fontSize:13,fontWeight:800,color:'#f87171'}}>Fine: ৳{Number(b.fine_amount).toFixed(2)}</div>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        ) : (
          <div style={{textAlign:'center',padding:'80px 0',color:'rgba(255,255,255,0.2)',fontSize:14,fontStyle:'italic'}}>
            No books borrowed yet
          </div>
        )
      )}
    </div>
  );
}
